`,inputSchema:{type:"object",properties:{limit:{type:"integer",minimum:1,maximum:100,description:"A limit on the number of objects to be returned. Limit can range between 1 and 100."},email:{type:"string",description:"A case-sensitive filter on the list based on the customer's email field. The value must be a string."}}}},{name:"create_product",description:`
