`,inputSchema:{type:"object",properties:{product:{type:"string",description:"The ID of the product to list prices for."},limit:{type:"integer",minimum:1,maximum:100,description:"A limit on the number of objects to be returned. Limit can range between 1 and 100, and the default is 10."}}}},{name:"create_payment_link",description:`
