`,inputSchema:{type:"object",properties:{customer:{type:"string",description:"The ID of the customer to create the invoice for."},days_until_due:{type:"integer",description:"The number of days until the invoice is due."}},required:["customer"]}},{name:"create_invoice_item",description:`
