`,inputSchema:{type:"object",properties:{payment_intent:{type:"string",description:"The ID of the PaymentIntent to refund."},amount:{type:"integer",description:"The amount to refund in cents."}},required:["payment_intent"]}},{name:"list_payment_intents",description:`
