`,inputSchema:{type:"object",properties:{customer:{type:"string",description:"The ID of the customer to list payment intents for."},limit:{type:"integer",minimum:1,maximum:100,description:"A limit on the number of objects to be returned. Limit can range between 1 and 100."}}}},{name:"search_documentation",description:`
