`,inputSchema:{type:"object",properties:{message:{type:"string",description:"Full users message"},searchQuery:{type:"string",description:"Generate a search query for 21st.dev (library for searching UI components) to find a UI component that matches the user's message. Must be a two-four words max or phrase"},absolutePathToCurrentFile:{type:"string",description:"Absolute path to the current file to which we want to apply changes"},absolutePathToProjectDirectory:{type:"string",description:"Absolute path to the project root directory"}},required:["message","searchQuery","absolutePathToCurrentFile","absolutePathToProjectDirectory"]}},{name:"logo_search",description:`
